// PermissionMultiSelect
// ---------------------------------------------------------------------------
function PermissionMultiSelect({
  permissions,
  selected,
  onChange,
  disabled,
}: {
  permissions: Permission[];
  selected: string[];
  onChange: (ids: string[]) => void;
  disabled?: boolean;
}) {
  // Group by module
  const grouped = permissions.reduce<Record<string, Permission[]>>((acc, p) => {
    if (!acc[p.module]) acc[p.module] = [];
    acc[p.module].push(p);
    return acc;
  }, {});

  function toggle(name: string) {
    if (disabled) return;
    onChange(
      selected.includes(name)
        ? selected.filter((x) => x !== name)
        : [...selected, name],
    );
  }

  function toggleModule(module: string) {
    if (disabled) return;
    const moduleNames = grouped[module].map((p) => p.name);
    const allSelected = moduleNames.every((name) => selected.includes(name));
    if (allSelected) {
      onChange(selected.filter((name) => !moduleNames.includes(name)));
    } else {
      const newSelected = [...new Set([...selected, ...moduleNames])];
      onChange(newSelected);
    }
  }

  return (
    <div
      style={{
        maxHeight: "240px",
        overflowY: "auto",
        border: "1px solid var(--io-border)",
        borderRadius: "var(--io-radius)",
        padding: "4px",
        opacity: disabled ? 0.6 : 1,
      }}
    >
      {Object.entries(grouped).map(([module, perms]) => {
        const allSelected = perms.every((p) => selected.includes(p.name));
        const someSelected = perms.some((p) => selected.includes(p.name));
        return (
          <div key={module} style={{ marginBottom: "4px" }}>
            <label
              style={{
                display: "flex",
                alignItems: "center",
                gap: "8px",
                padding: "8px 14px",
                cursor: disabled ? "not-allowed" : "pointer",
                borderRadius: "4px",
                background: "var(--io-surface-sunken)",
                fontSize: "12px",
                fontWeight: 600,
                color: "var(--io-text-muted)",
                textTransform: "uppercase",
                letterSpacing: "0.05em",
              }}
              onClick={() => toggleModule(module)}
            >
              <input
                type="checkbox"
                checked={allSelected}
                ref={(el) => {
                  if (el) el.indeterminate = !allSelected && someSelected;
                }}
                onChange={() => toggleModule(module)}
                style={{ accentColor: "var(--io-accent)" }}
                disabled={disabled}
              />
              {module}
            </label>
            {perms.map((p) => (
              <label
                key={p.id}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "8px",
                  padding: "4px 8px 4px 24px",
                  cursor: disabled ? "not-allowed" : "pointer",
                  fontSize: "12px",
                  color: "var(--io-text-primary)",
                }}
              >
                <input
                  type="checkbox"
                  checked={selected.includes(p.name)}
                  onChange={() => toggle(p.name)}
                  style={{ accentColor: "var(--io-accent)" }}
                  disabled={disabled}
                />
                <span>{p.name}</span>
                {p.description && (
                  <span
                    style={{
                      color: "var(--io-text-muted)",
                      fontSize: "11px",
                      marginLeft: "4px",
                    }}
                  >
                    — {p.description}
                  </span>
                )}
              </label>
            ))}
          </div>
        );
      })}
      {permissions.length === 0 && (
        <div
          style={{
            padding: "16px",
            textAlign: "center",
            color: "var(--io-text-muted)",
            fontSize: "13px",
          }}
        >
          No permissions available
        </div>
      )}
    </div>
  );
}

