              )}
              <span
                style={{
                  fontSize: 11,
                  color: "var(--io-text-muted)",
                  marginLeft: "auto",
                }}
              >
                {relativeTime(t.created_at_source ?? t.created_at)}
              </span>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

